SELECT IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")) AS DocumentType, [Sales Line].Type, [Sales Line].[Model Item No_], [Sales Line].[Unit of Measure], [Sales Line].[Variable Code 01], [Sales Line_1].[Assortment Code], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Order Date], [Sales Header].[Salesperson Code], [Sales Line].[Variable Code 01] AS ColorCode, [Sales Header].[Sell-to Customer No_], [Sales Line].[Document No_], [Sales Line].[Line No_], IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr","?"))))) AS TipoOrdine, Format(Month([Order date]),"00") & "/" & IIf(Day([order date])<11,"1",IIf(Day([order date])<21,"2","3")) AS OrderPeriod, IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs])) AS PairsSold, IIf([Sales Line.document type]=1,Val([Quantity]),-Val([Quantity])) AS QuantitySold, IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS SalesValue, Val([Quantity Shipped]) AS ShippedQuantity, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*Val([no_ of pairs]),0) AS PairsShipped, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*[SalesValue],0) AS ValueShipped, IIf(Val([quantity])>0,Val([Return Qty_ Received])/Val([quantity])*[SalesValue],0) AS ReturnedValue, -Val([Return Qty_ Received]) AS ReturnedQuantity, IIf(Val([quantity])>0,-Val([Return Qty_ Received])/Val([quantity])*Val([no_ of pairs]),0) AS ReturnedPairs, [Sales Line].[Return Reason Code] AS ReturnReasonCode, [Sales Header].[Ship-to Name] AS ClienteSpedizione, [Sales Header].[Ship-to Name 2] AS ClienteSpedizione2, [Sales Header].[Ship-to Address] AS IndirizzoSpedizione, [Sales Header].[Ship-to Address 2] AS IndirizzoSpedizione2, [Sales Header].[Ship-to City] AS CittaSpedizione, [Sales Header].[Ship-to Post Code] AS CodicePostaleSpedizione, [Sales Header].[Ship-to County] AS CountySpedizione, [Sales Line].[Requested Delivery Date], IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBolla]) AS PairsReadyForShipping, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbolla]) AS QuantityReadyForShipping, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,nz([quantitainbolla])/Val([quantity])*[SalesValue],0)) AS ValueReadyForShipping, Salesperson_Purchaser_1.Code AS CapozonaCodice, Salesperson_Purchaser_1.Name AS Capozona, [Variable Code].[Variable Code] AS Taglia, [Variable Code].[Order Variable Code] AS OrdinamentoTaglia
FROM ((((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [qsoloVend-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order No_])) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_1 ON [Sales Header].NSP_Capozona = Salesperson_Purchaser_1.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 02] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 02] = [Variable Code].[Variable Group])) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_]) AND ([Sales Line].[Document No_] = [Sales Line_1].[Document No_])
WHERE (((IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")))<>"") AND (([Sales Line].Type)=2));

